public static long solve(String s, long[] order, long k) {
    int n = s.length();
    boolean[] marked = new boolean[n];
    long total = 0;

    for (int t = 0; t < n; t++) {
        int index = (int) order[t];
        marked[index] = true;

        // Calculate the number of new valid substrings introduced by marking this position
        // A valid substring must contain at least one marked position
        // The total number of substrings is n*(n+1)/2
        // The number of invalid substrings (no marked positions) is sum of (len_i * (len_i + 1)/2) for each unmarked segment
        // So valid = total_substrings - invalid_substrings

        long totalSubstrings = (long) n * (n + 1) / 2;
        long invalid = 0;
        int currentLen = 0;

        for (int i = 0; i < n; i++) {
            if (!marked[i]) {
                currentLen++;
            } else {
                invalid += (long) currentLen * (currentLen + 1) / 2;
                currentLen = 0;
            }
        }
        invalid += (long) currentLen * (currentLen + 1) / 2;

        long valid = totalSubstrings - invalid;

        if (valid >= k) {
            return t;
        }
    }

    return -1;
}
